// Calculate date ranges for MQL comparison
const now = new Date();

// Past 7 days (current period)
const currentEnd = new Date();
const currentStart = new Date();
currentStart.setDate(currentStart.getDate() - 7);

// Previous 7 days (day 8-14 ago)
const previousEnd = new Date();
previousEnd.setDate(previousEnd.getDate() - 8);
const previousStart = new Date();
previousStart.setDate(previousStart.getDate() - 15);

// Same period last year (7 days, one year ago)
const lastYearEnd = new Date();
lastYearEnd.setFullYear(lastYearEnd.getFullYear() - 1);
const lastYearStart = new Date(lastYearEnd);
lastYearStart.setDate(lastYearStart.getDate() - 7);

return {
  json: {
    currentPeriod: {
      start: currentStart.getTime(),
      end: currentEnd.getTime(),
      label: `${currentStart.toLocaleDateString()} - ${currentEnd.toLocaleDateString()}`
    },
    previousPeriod: {
      start: previousStart.getTime(),
      end: previousEnd.getTime(),
      label: `${previousStart.toLocaleDateString()} - ${previousEnd.toLocaleDateString()}`
    },
    lastYearPeriod: {
      start: lastYearStart.getTime(),
      end: lastYearEnd.getTime(),
      label: `${lastYearStart.toLocaleDateString()} - ${lastYearEnd.toLocaleDateString()}`
    },
    hubspotToken: 'REPLACE_WITH_HUBSPOT_TOKEN',
    mqlListId: '873'
  }
};

// Combine all three period results and analyze lead quality
const currentResults = $input.all()[0].json.results || [];
const previousResults = $input.all()[1].json.results || [];
const lastYearResults = $input.all()[2].json.results || [];

// Helper function to analyze lead quality
function analyzeLeadQuality(leads) {
  const quality = {
    totalLeads: leads.length,
    industries: {},
    revenueRanges: {
      under100k: 0,
      '100k-1M': 0,
      '1M-10M': 0,
      '10M-100M': 0,
      over100M: 0,
      unknown: 0
    },
    jobTitles: {
      cLevel: 0,
      director: 0,
      manager: 0,
      coordinator: 0,
      other: 0,
      unknown: 0
    },
    topIndustries: [],
    topCompanies: []
  };

  const companies = {};

  leads.forEach(lead => {
    const props = lead.properties;

    // Analyze industry
    const industry = props.industry || 'Unknown';
    quality.industries[industry] = (quality.industries[industry] || 0) + 1;

    // Analyze revenue
    const revenue = parseFloat(props.annualrevenue) || 0;
    if (revenue === 0) {
      quality.revenueRanges.unknown++;
    } else if (revenue < 100000) {
      quality.revenueRanges.under100k++;
    } else if (revenue < 1000000) {
      quality.revenueRanges['100k-1M']++;
    } else if (revenue < 10000000) {
      quality.revenueRanges['1M-10M']++;
    } else if (revenue < 100000000) {
      quality.revenueRanges['10M-100M']++;
    } else {
      quality.revenueRanges.over100M++;
    }

    // Analyze job title
    const jobTitle = (props.jobtitle || '').toLowerCase();
    if (!jobTitle) {
      quality.jobTitles.unknown++;
    } else if (jobTitle.includes('ceo') || jobTitle.includes('cto') || jobTitle.includes('cfo') || jobTitle.includes('cmo') || jobTitle.includes('chief')) {
      quality.jobTitles.cLevel++;
    } else if (jobTitle.includes('director') || jobTitle.includes('vp') || jobTitle.includes('vice president') || jobTitle.includes('head of')) {
      quality.jobTitles.director++;
    } else if (jobTitle.includes('manager')) {
      quality.jobTitles.manager++;
    } else if (jobTitle.includes('coordinator') || jobTitle.includes('specialist') || jobTitle.includes('associate')) {
      quality.jobTitles.coordinator++;
    } else {
      quality.jobTitles.other++;
    }

    // Track companies
    const company = props.company || 'Unknown';
    companies[company] = (companies[company] || 0) + 1;
  });

  // Get top 5 industries
  quality.topIndustries = Object.entries(quality.industries)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([industry, count]) => ({ industry, count }));

  // Get top 5 companies
  quality.topCompanies = Object.entries(companies)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([company, count]) => ({ company, count }));

  return quality;
}

// Calculate quality scores
const currentQuality = analyzeLeadQuality(currentResults);
const previousQuality = analyzeLeadQuality(previousResults);
const lastYearQuality = analyzeLeadQuality(lastYearResults);

// Calculate changes
function calculateChange(current, previous) {
  if (previous === 0) return current > 0 ? 100 : 0;
  return parseFloat((((current - previous) / previous) * 100).toFixed(1));
}

const vsPrevious = {
  absolute: currentQuality.totalLeads - previousQuality.totalLeads,
  percentage: calculateChange(currentQuality.totalLeads, previousQuality.totalLeads)
};

const vsLastYear = {
  absolute: currentQuality.totalLeads - lastYearQuality.totalLeads,
  percentage: calculateChange(currentQuality.totalLeads, lastYearQuality.totalLeads)
};

// Calculate quality score (higher revenue + higher seniority = better quality)
function calculateQualityScore(quality) {
  const highValueRevenue = quality.revenueRanges['10M-100M'] + quality.revenueRanges.over100M;
  const seniorTitles = quality.jobTitles.cLevel + quality.jobTitles.director;
  const totalLeads = quality.totalLeads || 1;

  const revenueScore = (highValueRevenue / totalLeads) * 50;
  const seniorityScore = (seniorTitles / totalLeads) * 50;

  return parseFloat((revenueScore + seniorityScore).toFixed(1));
}

const currentQualityScore = calculateQualityScore(currentQuality);
const previousQualityScore = calculateQualityScore(previousQuality);
const lastYearQualityScore = calculateQualityScore(lastYearQuality);

// Generate insights
const insights = [];

if (vsPrevious.absolute < 0) {
  insights.push(`⚠️ MQL volume down ${Math.abs(vsPrevious.absolute)} leads vs previous week`);
} else if (vsPrevious.absolute > 0) {
  insights.push(`✅ MQL volume up ${vsPrevious.absolute} leads vs previous week`);
}

if (currentQualityScore > previousQualityScore) {
  insights.push(`✅ Lead quality improved (score: ${currentQualityScore} vs ${previousQualityScore})`);
} else if (currentQualityScore < previousQualityScore) {
  insights.push(`⚠️ Lead quality declined (score: ${currentQualityScore} vs ${previousQualityScore})`);
}

const highValueLeads = currentQuality.revenueRanges['10M-100M'] + currentQuality.revenueRanges.over100M;
if (highValueLeads > 0) {
  insights.push(`💎 ${highValueLeads} high-value leads (>$10M revenue)`);
}

const seniorLeads = currentQuality.jobTitles.cLevel + currentQuality.jobTitles.director;
if (seniorLeads > 0) {
  insights.push(`👔 ${seniorLeads} senior decision-makers (C-level/Director+)`);
}

if (currentQuality.topIndustries.length > 0) {
  const topIndustry = currentQuality.topIndustries[0];
  insights.push(`🏢 Top industry: ${topIndustry.industry} (${topIndustry.count} leads)`);
}

return {
  json: {
    reportDate: new Date().toISOString(),
    summary: {
      currentPeriod: {
        label: $('Calculate Date Ranges').item.json.currentPeriod.label,
        totalMQLs: currentQuality.totalLeads,
        qualityScore: currentQualityScore
      },
      previousPeriod: {
        label: $('Calculate Date Ranges').item.json.previousPeriod.label,
        totalMQLs: previousQuality.totalLeads,
        qualityScore: previousQualityScore
      },
      lastYearPeriod: {
        label: $('Calculate Date Ranges').item.json.lastYearPeriod.label,
        totalMQLs: lastYearQuality.totalLeads,
        qualityScore: lastYearQualityScore
      },
      comparisons: {
        vsPreviousWeek: vsPrevious,
        vsLastYear: vsLastYear
      }
    },
    leadQuality: {
      current: currentQuality,
      previous: previousQuality,
      lastYear: lastYearQuality
    },
    insights: insights,
    rawData: {
      currentLeads: currentResults,
      previousLeads: previousResults,
      lastYearLeads: lastYearResults
    }
  }
};
